22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	
25	const ITEM_BASE_PREMIUM: Record<string, number> = {
26	  sword: 100,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_PREMIUM = 60;
34	
35	const groupCountsByType = (items: Item[]): Map<string, number> => {
36	  const counts = new Map<string, number>();
37	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
38	  return counts;
39	};
40	
41	const basePremiumForGroup = (type: string, count: number): number => {
42	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
43	  return count * ITEM_BASE_PREMIUM[type];
44	};
45	
46	const calculatePremium = (items: Item[]): number => {
47	  const counts = groupCountsByType(items);
48	  let base = 0;
49	  for (const [type, count] of counts) base += basePremiumForGroup(type, count);
50	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE;
51	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
52	};
53	
54	export const runScenario = (scenario: Scenario): ScenarioResult => {
55	  const results = scenario.steps.map((step) => ({
56	    premium: calculatePremium(step.items ?? []),
57	  }));
58	  return { results };
59	};
60

